		function ViewReclutado()
{
	openNewFlowWait('NucleusRH.Base.Gestion_de_Postulantes.Reclutados.flow',"init_contrato","<FILTRO oi_reclutado=\""+Ctrl('oi_reclutado').GetXValue()+"\" oi_empresa=\""+Ctrl('oi_empresa').GetXValue()+"\" />",new ObjtectResult(),"L");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin)
	{    
	}
}          

function setReferencia()
{
	//Seteo la referencia a traves del oi_req
	var nSQL = GetProxy().SQLService();   
	var xml = nSQL.GetOBJ(Ctrl("main").getResource("qry_referencia"), "<PARAM oi_req=\""+Ctrl("oi_req").GetXValue()+"\" />");
	Ctrl("oi_referencia").SetXValue(xml.oi_referencia); 
}
